// Resolve the start timestamp regardless of which trigger fired.
const body = ($json && $json.body) ? $json.body : {};
return [{
  json: {
    startTs: body.startTs || Date.now(),
    triggeredBy: body.startTs ? 'manual' : 'schedule',
  },
}];

// Aggregate yesterday's row from the DailyData sheet.
// Expected columns: Date, Leads, HotLeads, InvoicesSent, TotalInvoiced.
// If no row matches yesterday, fall back to the latest row.
const rows = $input.all().map(i => i.json);
const meta = $('Init Run').item.json;

function toYmd(d) {
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
const targetDate = toYmd(yesterday);

let row = rows.find(r => String(r.Date || '').slice(0, 10) === targetDate);
if (!row && rows.length > 0) row = rows[rows.length - 1];
if (!row) row = { Date: targetDate, Leads: 0, HotLeads: 0, InvoicesSent: 0, TotalInvoiced: 0 };

const summaryDate = String(row.Date || targetDate).slice(0, 10);
const leads = Number(row.Leads || 0);
const hotLeads = Number(row.HotLeads || 0);
const invoicesSent = Number(row.InvoicesSent || 0);
const totalInvoiced = Number(row.TotalInvoiced || 0);

return [{
  json: {
    ...meta,
    summaryDate,
    leads,
    hotLeads,
    invoicesSent,
    totalInvoiced,
  },
}];

