// Build the email HTML body around Claude's digest text.
const meta = $('Aggregate Yesterday').item.json;
const claudeResp = $json;

function extractText(node) {
  if (node && Array.isArray(node.content) && node.content[0] && typeof node.content[0].text === 'string') {
    return node.content[0].text;
  }
  throw new Error('Could not extract Claude digest text');
}

const digestText = extractText(claudeResp).trim();
const paragraphs = digestText.split(/\n\s*\n/).map(p => `<p style="margin:0 0 14px;font-size:15px;line-height:1.65;color:#1c1c1c;">${p.trim()}</p>`).join('');

const html = `<!doctype html>
<html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;background:#f7f7f5;margin:0;padding:24px;">
  <div style="max-width:580px;margin:0 auto;background:#ffffff;border:1px solid #e5e5e0;border-radius:12px;overflow:hidden;">
    <div style="padding:20px 28px;border-bottom:1px solid #e5e5e0;background:#0f172a;color:#ffffff;">
      <div style="font-size:11px;letter-spacing:0.12em;text-transform:uppercase;opacity:0.7;margin-bottom:4px;">Daily Digest</div>
      <div style="font-size:18px;font-weight:600;">Your morning brief — ${meta.summaryDate}</div>
    </div>
    <div style="padding:24px 28px;">
      <p style="margin:0 0 18px;font-size:15px;color:#1c1c1c;">Good morning,</p>
      ${paragraphs}
      <table style="width:100%;border-collapse:collapse;margin-top:18px;border-top:1px solid #e5e5e0;padding-top:14px;">
        <tr>
          <td style="padding:6px 0;font-size:13px;color:#64748b;">New leads</td>
          <td style="padding:6px 0;font-size:13px;color:#1c1c1c;text-align:right;font-weight:600;">${meta.leads}</td>
        </tr>
        <tr>
          <td style="padding:6px 0;font-size:13px;color:#64748b;">Hot leads</td>
          <td style="padding:6px 0;font-size:13px;color:#dc2626;text-align:right;font-weight:600;">${meta.hotLeads}</td>
        </tr>
        <tr>
          <td style="padding:6px 0;font-size:13px;color:#64748b;">Invoices sent</td>
          <td style="padding:6px 0;font-size:13px;color:#1c1c1c;text-align:right;font-weight:600;">${meta.invoicesSent}</td>
        </tr>
        <tr>
          <td style="padding:6px 0;font-size:13px;color:#64748b;">Total invoiced</td>
          <td style="padding:6px 0;font-size:13px;color:#15803d;text-align:right;font-weight:600;">$${meta.totalInvoiced.toFixed(2)}</td>
        </tr>
      </table>
    </div>
    <div style="padding:14px 28px;border-top:1px solid #e5e5e0;background:#fafaf8;font-size:11px;color:#94a3b8;">
      Generated by Cenred AI Automation Dashboard · Triggered ${meta.triggeredBy}
    </div>
  </div>
</body></html>`;

return [{
  json: {
    ...meta,
    digestText,
    html,
  },
}];
